const body = $('Webhook').item.json.body;
const messageBody = body.Body || '';
const fromPhone = body.From || '';
const toPhone = body.To || '';
return [{ json: { message_body: messageBody, from_phone: fromPhone, to_phone: toPhone, raw: body } }];

const rawText = $('Parse SMS Fields').item.json.message_body || '';
const techName = rawText.trim();
if (!techName) {
  throw new Error('[E02S02] Empty message_body — no tech name to match');
}
return [{ json: { tech_name: techName } }];

const jobId = $('Get Latest New Job').item.json.id;
const jobShort = jobId.slice(-6).toUpperCase();
const techName = $('Get Tech by Name').item.json.name;
const dispatcherPhone = $('Parse SMS Fields').item.json.from_phone;
const fromNumber = $('Get Client by Phone').item.json.twilio_number;

if (!jobId) throw new Error('[E02S02] job ID missing');
if (!techName) throw new Error('[E02S02] tech name missing');
if (!dispatcherPhone) throw new Error('[E02S02] dispatcher phone missing');
if (!fromNumber) throw new Error('[E02S02] from_number missing');

const confirmMsg = `Job #${jobShort} assigned to ${techName}.`;

return [{
  json: {
    confirmation_msg: confirmMsg,
    dispatcher_phone: dispatcherPhone,
    from_number: fromNumber
  }
}];

const allTechs = $input.all();
const techNames = allTechs.map(item => item.json.name).filter(Boolean).join(', ');
const attempted = $('Extract Tech Name').item.json.tech_name;
const dispatcherPhone = $('Parse SMS Fields').item.json.from_phone;
const fromNumber = $('Get Client by Phone').item.json.twilio_number;

if (!dispatcherPhone) throw new Error('[E02S03] dispatcher_phone missing');
if (!fromNumber) throw new Error('[E02S03] from_number (twilio_number) missing');

const errorMsg = `No match for '${attempted}'. Valid techs: ${techNames}. Reply with a name to assign.`;

return [{
  json: {
    error_msg: errorMsg,
    dispatcher_phone: dispatcherPhone,
    from_number: fromNumber
  }
}];

// E02S04: Build 'already assigned' guard SMS for dispatcher
// AC3: 'Job #[ID] is already [status]. Assigned to [Tech Name].'
// AC4: If no tech assigned, omit tech name gracefully

const job = $('Get Current Job State').item.json;
const dispatcherPhone = $('Parse SMS Fields').item.json.from_phone;
const fromNumber = $('Get Client by Phone').item.json.twilio_number;

if (!dispatcherPhone) throw new Error('[E02S04] dispatcher_phone missing');
if (!fromNumber) throw new Error('[E02S04] from_number (twilio_number) missing');

let guardMsg;

if (!job || !job.id) {
  // Edge case: no jobs at all for this client
  guardMsg = 'No active job found for your number. Please check and try again.';
} else {
  // AC3: Build message with job ID (last 6 chars, uppercased) + current status
  const jobShort = job.id.slice(-6).toUpperCase();
  const currentStatus = job.status || 'Unknown';

  // AC4: Include tech name only if a tech is assigned
  const techName = job.techs && job.techs.name ? job.techs.name : null;

  if (techName) {
    guardMsg = `Job #${jobShort} is already ${currentStatus}. Assigned to ${techName}.`;
  } else {
    guardMsg = `Job #${jobShort} is already ${currentStatus}.`;
  }
}

return [{
  json: {
    guard_msg: guardMsg,
    dispatcher_phone: dispatcherPhone,
    from_number: fromNumber
  }
}];
